    base_rate, nabh_incentive, effective_rate, implant_name, implant_cost, total_with_implant,
    level_of_care, alos, is_day_care, auto_approved, pre_auth_docs, claim_docs)
WHERE c.code = 'SHJ' OR c.name ILIKE '%shilaj%'
ON CONFLICT (centre_id, procedure_code) DO UPDATE SET
    package_code = EXCLUDED.package_code, specialty = EXCLUDED.specialty,
    package_name = EXCLUDED.package_name, procedure_name = EXCLUDED.procedure_name,
    base_rate = EXCLUDED.base_rate, nabh_incentive = EXCLUDED.nabh_incentive,
    effective_rate = EXCLUDED.effective_rate, implant_name = EXCLUDED.implant_name,
    implant_cost = EXCLUDED.implant_cost, total_with_implant = EXCLUDED.total_with_implant,
    level_of_care = EXCLUDED.level_of_care, alos = EXCLUDED.alos,
    is_day_care = EXCLUDED.is_day_care, auto_approved = EXCLUDED.auto_approved,
    pre_auth_docs = EXCLUDED.pre_auth_docs, claim_docs = EXCLUDED.claim_docs;

-- Also update hmis_tariff_master rate_pmjay for matching services
-- This links PMJAY rates to the billing tariff
UPDATE hmis_tariff_master t SET
    rate_pmjay = p.effective_rate
FROM hmis_pmjay_packages p
WHERE t.centre_id = p.centre_id
  AND (
    UPPER(t.service_name) ILIKE '%' || UPPER(SPLIT_PART(p.package_name, ' ', 1)) || '%'
    OR UPPER(t.service_name) ILIKE '%' || UPPER(SPLIT_PART(p.package_name, ' ', 2)) || '%'
  )
  AND t.rate_pmjay < p.effective_rate;
